SELECT T.JOB_NM ,T.JOB_DATE ,T.JOB_END_DATE ,T.JOB_RLT ,T.JOB_RLT_MSG FROM (SELECT (CASE BL.JOB_ID WHEN 'HDxxxxJob' THEN '' ELSE '' END) AS JOB_NM ,(BL.JOB_DATE, 'YYYY-MM-DD HH24:MI') AS JOB_DATE ,(BL.JOB_END_DATE, 'YYYY-MM-DD HH24:MI') AS JOB_END_DATE ,BL.JOB_RLT ,(CASE BL.JOB_RLT WHEN 'E' THEN BL.JOB_RLT_MSG ELSE '' END) as JOB_RLT_MSG FROM STOCBLOG BL WHERE BL.JOB_TYPE = 'Batch'
AND BL.JOB_DATE >= (#{JOB_DATE_FROM}) AND BL.JOB_DATE <= (#{JOB_DATE_TO})
AND BL.JOB_ID = #{JOB_NM}
AND BL.JOB_RLT = #{JOB_RLT}
) T WHERE 1 = 1 ORDER BY T.JOB_DATE DESC


		SELECT TEXT_SQ, TEXT_CONTENTS
		  FROM STOCTXTD
		 WHERE GATE_CD  = #{GATE_CD}
           AND TEXT_NUM = #{TEXT_NUM}
         ORDER BY TEXT_SQ

